// Formater les résultats de la recherche pour l'agent IA
const response = $input.item.json.result || $input.item.json;
const results = response.results || [];

if (results.length === 0) {
  return {
    json: {
      success: true,
      message: "Aucun résultat trouvé dans la documentation.",
      results: []
    }
  };
}

let formattedText = `J'ai trouvé ${results.length} résultat(s) dans la documentation BunkerWeb`;
if (response.query) {
  formattedText += ` pour "${response.query}"`;
}
formattedText += ` :\n\n`;

results.forEach((doc, idx) => {
  formattedText += `${idx + 1}. **${doc.title}**`;
  if (doc.category) {
    formattedText += ` (${doc.category})`;
  }
  formattedText += `\n`;

  const score = doc.relevance_score || doc.score || 0;
  formattedText += `   Score de pertinence: ${(score * 100).toFixed(0)}%\n`;
  formattedText += `   ${doc.content.substring(0, 300)}...\n`;
  formattedText += `   📖 Lien: ${doc.url}\n\n`;
});

return {
  json: {
    success: true,
    message: formattedText,
    raw_results: results,
    count: results.length,
    query: response.query || null
  }
};
